query getProductDetail($skuIds: [String!]!) {
  productsBySkuIds(skuIds: $skuIds) {
    ... on Product {
      skuId
      brand
      whatItIs
      name {
        short
        __typename
      }
      description {
        long
        __typename
      }
      primaryImage {
        piscesHref
        __typename
      }
      __typename
      openBoxCondition
    }
    __typename
  }
}
